-- Entfernen: DELETE FROM invoice_templates WHERE produktnummer LIKE 'KALK-%';
DO $$ DECLARE owner_id uuid; BEGIN
  SELECT user_id INTO owner_id FROM public.user_roles WHERE role='administrator' LIMIT 1;
  IF owner_id IS NULL THEN SELECT id INTO owner_id FROM auth.users ORDER BY created_at LIMIT 1; END IF;
  DELETE FROM public.invoice_templates WHERE produktnummer LIKE 'KALK-%';
END $$;